"use client";

import React, { useRef } from "react";
import { motion, useReducedMotion, useScroll, useTransform } from "motion/react";

type Intensity = "subtle" | "medium";

export interface ParallaxDepthProps {
  /** background image URL — a full-bleed layer that drifts slower than the foreground */
  image: string;
  /** foreground content that sits over the parallax backdrop */
  children?: React.ReactNode;
  intensity?: Intensity;
  /** section min-height, e.g. "80vh" */
  minHeight?: string;
  className?: string;
  /** dark scrim (0-1) so foreground text stays readable over the photo */
  overlay?: number;
}

/*
 * Depth parallax: the background media layer scrolls slower than the foreground content, implying
 * depth. SAFETY IS BAKED IN, not left to the caller - prefers-reduced-motion freezes the image (no
 * drift), the drift magnitude is CLAMPED by `intensity` to a range whose oversized layer (scale)
 * always overscans further than the shift, so an edge gap can never appear, and a readability scrim
 * defaults on. The agent supplies only the image + foreground content (+ optional intensity); a bad
 * prop degrades to a plain static hero. Only transform is animated (GPU), never layout.
 */
export function ParallaxDepth({
  image,
  children,
  intensity = "subtle",
  minHeight = "80vh",
  className,
  overlay = 0.35,
}: ParallaxDepthProps) {
  const ref = useRef<HTMLElement>(null);
  const reduced = useReducedMotion();
  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start end", "end start"],
  });
  // subtle: +/-8% drift on a 1.3x layer (15% overscan each side); medium: +/-14% on 1.4x (20%).
  // Overscan always exceeds the drift, so the image never reveals an edge.
  const cfg = intensity === "medium" ? { shift: 14, scale: 1.4 } : { shift: 8, scale: 1.3 };
  const y = useTransform(scrollYProgress, [0, 1], ["-" + cfg.shift + "%", cfg.shift + "%"]);

  return (
    <section ref={ref} className={className} style={{ position: "relative", minHeight, overflow: "hidden" }}>
      <motion.div
        aria-hidden
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: "url(" + image + ")",
          backgroundSize: "cover",
          backgroundPosition: "center",
          scale: cfg.scale,
          y: reduced ? "0%" : y,
          willChange: "transform",
        }}
      />
      {overlay > 0 ? (
        <div aria-hidden style={{ position: "absolute", inset: 0, background: "rgba(0,0,0," + overlay + ")" }} />
      ) : null}
      <div style={{ position: "relative", zIndex: 1 }}>{children}</div>
    </section>
  );
}

export default ParallaxDepth;
